import{_ as t,c as a,o as i,aj as n}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Application Development","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices/application-development.md","filePath":"guide/best-practices/application-development.md","lastUpdated":1777621302000}'),s={name:"guide/best-practices/application-development.md"};function o(r,e,l,c,d,p){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="application-development" tabindex="-1">Application Development <a class="header-anchor" href="#application-development" aria-label="Permalink to &quot;Application Development&quot;">​</a></h1><p>Iroha applications should make transaction behavior explicit, keep signing state contained, and use queries and events in ways that are easy to observe in production.</p><h2 id="client-setup" tabindex="-1">Client Setup <a class="header-anchor" href="#client-setup" aria-label="Permalink to &quot;Client Setup&quot;">​</a></h2><ul><li>Store client configuration outside application source code. Load the chain ID, Torii URL, signing account, and transaction settings from environment-specific config.</li><li>Keep <code>client.toml</code> files separate for localnet, Taira, Minamoto, and private networks. A copied testnet signer should never become a mainnet signer.</li><li>Set transaction lifetimes and status timeouts deliberately. A very short lifetime can expire under normal network jitter, while a very long one can make duplicate submissions harder to reason about.</li><li>Use <code>nonce = true</code> only when repeated transactions should have distinct hashes. For idempotent business operations, store and reuse an application request ID so retries are traceable.</li></ul><p>See <a href="/iroha-2-docs/guide/configure/client-configuration.html">Client Configuration</a> for the current TOML fields.</p><h2 id="transactions" tabindex="-1">Transactions <a class="header-anchor" href="#transactions" aria-label="Permalink to &quot;Transactions&quot;">​</a></h2><ul><li>Build transactions from typed SDK instructions where possible instead of raw JSON or string-assembled payloads.</li><li>Preflight important writes with read-only queries: account existence, asset balances, permission state, fee asset availability, and target object state.</li><li>Record the transaction hash, authority account, instruction summary, and expected state change before submitting.</li><li>Treat <code>Rejected</code>, <code>Expired</code>, and timeout outcomes differently. A timeout means the client did not observe a final status; it does not prove that the network ignored the transaction.</li><li>After a successful write, verify the resulting state with a query or event checkpoint that matches the business operation.</li></ul><p>For transaction mechanics, see <a href="/iroha-2-docs/blockchain/transactions.html">Transactions</a>.</p><h2 id="queries-and-events" tabindex="-1">Queries and Events <a class="header-anchor" href="#queries-and-events" aria-label="Permalink to &quot;Queries and Events&quot;">​</a></h2><ul><li>Use queries for current state and event streams for change notifications. Avoid replacing event handling with repeated broad queries.</li><li>Paginate broad iterable queries such as account, asset, and block listings.</li><li>Prefer narrow filters for subscriptions and triggers. Broad filters are useful for diagnostics but can add unnecessary execution and client-side processing.</li><li>Keep read-only smoke checks separate from signed transaction tests so endpoint availability is easier to diagnose.</li></ul><p>See <a href="/iroha-2-docs/blockchain/queries.html">Queries</a>, <a href="/iroha-2-docs/blockchain/events.html">Events</a>, and <a href="/iroha-2-docs/blockchain/filters.html">Filters</a>.</p><h2 id="agent-assisted-development" tabindex="-1">Agent-Assisted Development <a class="header-anchor" href="#agent-assisted-development" aria-label="Permalink to &quot;Agent-Assisted Development&quot;">​</a></h2><ul><li>Let agents inspect docs, SDK code, and read-only network state before asking them to write transaction code.</li><li>Keep live-network tests opt-in behind an environment flag such as <code>TAIRA_LIVE=1</code>.</li><li>Do not paste private keys, account recovery material, API tokens, or forwarded auth headers into prompts.</li><li>Require a transaction plan before any agent submits a live testnet transaction. The plan should name the network, authority, instructions, fee asset, preflight reads, expected result, and retry behavior.</li></ul><p>For the Taira MCP workflow, see <a href="/iroha-2-docs/get-started/sora-nexus-dataspaces.html#taira-mcp-for-agents">Build on SORA 3: Taira and Minamoto</a>.</p><h2 id="sdk-hygiene" tabindex="-1">SDK Hygiene <a class="header-anchor" href="#sdk-hygiene" aria-label="Permalink to &quot;SDK Hygiene&quot;">​</a></h2><ul><li>Pin SDK and binary versions together using the <a href="/iroha-2-docs/reference/compatibility-matrix.html">Compatibility Matrix</a>.</li><li>Keep generated client code, snippets, and examples synchronized with the upstream workspace rather than copying older Iroha 2 examples forward.</li><li>Add unit tests for transaction-building code and integration tests for the smallest read and write paths your application depends on.</li></ul>',16)])])}const m=t(s,[["render",o]]);export{u as __pageData,m as default};
